import React from "react";

const MACHINES = [
  { src: "/air_to_water_heat_pump.svg", left: "4%", top: "12%", size: 130, duration: 28, delay: 0 },
  { src: "/air_to_air_heat_pump_correct.svg", left: "72%", top: "8%", size: 110, duration: 24, delay: 3 },
  { src: "/water_to_water_heat_pump.svg", left: "78%", top: "58%", size: 145, duration: 32, delay: 5 },
  { src: "/ground_source_heat_pump.svg", left: "8%", top: "62%", size: 120, duration: 26, delay: 8 },
  { src: "/air_to_water_heat_pump.svg", left: "42%", top: "78%", size: 95, duration: 22, delay: 4 },
  { src: "/air_to_air_heat_pump_correct.svg", left: "55%", top: "22%", size: 85, duration: 30, delay: 10 },
];

export default function BackgroundMachines() {
  return (
    <div className="bg-machines" aria-hidden="true">
      {MACHINES.map((m, i) => (
        <img
          key={i}
          className="bg-machine"
          src={m.src}
          alt=""
          style={{
            left: m.left,
            top: m.top,
            width: m.size,
            height: m.size,
            animationDuration: `${m.duration}s`,
            animationDelay: `${m.delay}s`,
          }}
        />
      ))}
    </div>
  );
}
